#define OPEN
#define ITERATION
#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <cuda.h>

#ifdef BLOCK_SIZE
#define BLOCK_DIM BLOCK_SIZE
#else
#define BLOCK_DIM 16
#endif

void random_matrix(float *I, int rows, int cols);

// CUDA kernel for computing c values
__global__ void compute_c_kernel(float *J, float *dN, float *dS, float *dW, float *dE, 
                                  float *c, int *iN, int *iS, int *jW, int *jE,
                                  int rows, int cols, float q0sqr)
{
    int i = blockIdx.y * blockDim.y + threadIdx.y;
    int j = blockIdx.x * blockDim.x + threadIdx.x;
    int k = i * cols + j;

    if (i < rows && j < cols) {
        float Jc = J[k];

        dN[k] = J[iN[i] * cols + j] - Jc;
        dS[k] = J[iS[i] * cols + j] - Jc;
        dW[k] = J[i * cols + jW[j]] - Jc;
        dE[k] = J[i * cols + jE[j]] - Jc;

        float G2 = (dN[k]*dN[k] + dS[k]*dS[k] + dW[k]*dW[k] + dE[k]*dE[k]) / (Jc*Jc);
        float L = (dN[k] + dS[k] + dW[k] + dE[k]) / Jc;

        float num = (0.5*G2) - ((1.0/16.0)*(L*L));
        float den = 1 + (.25*L);
        float qsqr = num/(den*den);

        den = (qsqr-q0sqr) / (q0sqr * (1+q0sqr));
        c[k] = 1.0 / (1.0+den);

        if (c[k] < 0) c[k] = 0;
        else if (c[k] > 1) c[k] = 1;
    }
}

// CUDA kernel for updating J values
__global__ void update_J_kernel(float *J, float *c, float *dN, float *dS, float *dW, float *dE,
                                 int *iN, int *iS, int *jW, int *jE,
                                 int rows, int cols, float lambda)
{
    int i = blockIdx.y * blockDim.y + threadIdx.y;
    int j = blockIdx.x * blockDim.x + threadIdx.x;
    int k = i * cols + j;

    if (i < rows && j < cols) {
        float cN = c[k];
        float cS = c[iS[i] * cols + j];
        float cW = c[k];
        float cE = c[i * cols + jE[j]];

        float D = cN * dN[k] + cS * dS[k] + cW * dW[k] + cE * dE[k];

        J[k] = J[k] + 0.25*lambda*D;
    }
}

void usage(int argc, char **argv)
{
	fprintf(stderr, "Usage: %s <rows> <cols> <y1> <y2> <x1> <x2> <no. of threads><lamda> <no. of iter>\n", argv[0]);
	fprintf(stderr, "\t<rows>   - number of rows\n");
	fprintf(stderr, "\t<cols>    - number of cols\n");
	fprintf(stderr, "\t<y1> 	 - y1 value of the speckle\n");
	fprintf(stderr, "\t<y2>      - y2 value of the speckle\n");
	fprintf(stderr, "\t<x1>       - x1 value of the speckle\n");
	fprintf(stderr, "\t<x2>       - x2 value of the speckle\n");
	fprintf(stderr, "\t<no. of threads>  - no. of threads\n");
	fprintf(stderr, "\t<lamda>   - lambda (0,1)\n");
	fprintf(stderr, "\t<no. of iter>   - number of iterations\n");

	exit(1);
}

int main(int argc, char* argv[])
{   
	int rows, cols, size_I, size_R, niter = 10, iter, k;
    float *I, *J, q0sqr, sum, sum2, tmp, meanROI,varROI ;
	float Jc, G2, L, num, den, qsqr;
	int *iN,*iS,*jE,*jW;
	float *dN,*dS,*dW,*dE;
	int r1, r2, c1, c2;
	float cN,cS,cW,cE;
	float *c, D;
	float lambda;
	int i, j;
    int nthreads;

	if (argc == 10)
	{
		rows = atoi(argv[1]); 
		cols = atoi(argv[2]); 
		if ((rows%16!=0) || (cols%16!=0)){
			fprintf(stderr, "rows and cols must be multiples of 16\n");
			exit(1);
		}
		r1   = atoi(argv[3]); 
		r2   = atoi(argv[4]); 
		c1   = atoi(argv[5]); 
		c2   = atoi(argv[6]); 
		nthreads = atoi(argv[7]); 
		lambda = atof(argv[8]); 
		niter = atoi(argv[9]); 
	}
    else{
		usage(argc, argv);
    }


	size_I = cols * rows;
    size_R = (r2-r1+1)*(c2-c1+1);   

	I = (float *)malloc( size_I * sizeof(float) );
    J = (float *)malloc( size_I * sizeof(float) );
	c  = (float *)malloc(sizeof(float)* size_I) ;

    iN = (int *)malloc(sizeof(int) * rows) ;
    iS = (int *)malloc(sizeof(int) * rows) ;
    jW = (int *)malloc(sizeof(int) * cols) ;
    jE = (int *)malloc(sizeof(int) * cols) ;    


	dN = (float *)malloc(sizeof(float)* size_I) ;
    dS = (float *)malloc(sizeof(float)* size_I) ;
    dW = (float *)malloc(sizeof(float)* size_I) ;
    dE = (float *)malloc(sizeof(float)* size_I) ;    


    for (int i=0; i< rows; i++) {
        iN[i] = i-1;
        iS[i] = i+1;
    }    
    for (int j=0; j< cols; j++) {
        jW[j] = j-1;
        jE[j] = j+1;
    }
    iN[0]    = 0;
    iS[rows-1] = rows-1;
    jW[0]    = 0;
    jE[cols-1] = cols-1;

	printf("Randomizing the input matrix\n");

    random_matrix(I, rows, cols);

    for (k = 0;  k < size_I; k++ ) {
     	J[k] = (float)exp(I[k]) ;
    }

	printf("Start the SRAD main loop\n");

	// CUDA device memory allocation
	float *d_J, *d_dN, *d_dS, *d_dW, *d_dE, *d_c;
	int *d_iN, *d_iS, *d_jW, *d_jE;

	cudaMalloc(&d_J, size_I * sizeof(float));
	cudaMalloc(&d_dN, size_I * sizeof(float));
	cudaMalloc(&d_dS, size_I * sizeof(float));
	cudaMalloc(&d_dW, size_I * sizeof(float));
	cudaMalloc(&d_dE, size_I * sizeof(float));
	cudaMalloc(&d_c, size_I * sizeof(float));
	cudaMalloc(&d_iN, rows * sizeof(int));
	cudaMalloc(&d_iS, rows * sizeof(int));
	cudaMalloc(&d_jW, cols * sizeof(int));
	cudaMalloc(&d_jE, cols * sizeof(int));

	// Copy data to device
	cudaMemcpy(d_J, J, size_I * sizeof(float), cudaMemcpyHostToDevice);
	cudaMemcpy(d_iN, iN, rows * sizeof(int), cudaMemcpyHostToDevice);
	cudaMemcpy(d_iS, iS, rows * sizeof(int), cudaMemcpyHostToDevice);
	cudaMemcpy(d_jW, jW, cols * sizeof(int), cudaMemcpyHostToDevice);
	cudaMemcpy(d_jE, jE, cols * sizeof(int), cudaMemcpyHostToDevice);

	// Setup kernel dimensions
	dim3 blockDim(BLOCK_DIM, BLOCK_DIM);
	dim3 gridDim((cols + BLOCK_DIM - 1) / BLOCK_DIM, (rows + BLOCK_DIM - 1) / BLOCK_DIM);

#ifdef ITERATION
	for (iter=0; iter< niter; iter++){
#endif        
		sum=0; sum2=0;     
		for (i=r1; i<=r2; i++) {
            for (j=c1; j<=c2; j++) {
                tmp   = J[i * cols + j];
                sum  += tmp ;
                sum2 += tmp*tmp;
            }
        }
        meanROI = sum / size_R;
        varROI  = (sum2 / size_R) - meanROI*meanROI;
        q0sqr   = varROI / (meanROI*meanROI);


#ifdef OPEN
		// Launch compute_c kernel
		compute_c_kernel<<<gridDim, blockDim>>>(d_J, d_dN, d_dS, d_dW, d_dE, d_c, d_iN, d_iS, d_jW, d_jE, rows, cols, q0sqr);
		cudaDeviceSynchronize();
#endif    

    }
#ifdef OPEN
		// Launch update_J kernel
		update_J_kernel<<<gridDim, blockDim>>>(d_J, d_c, d_dN, d_dS, d_dW, d_dE, d_iN, d_iS, d_jW, d_jE, rows, cols, lambda);
		cudaDeviceSynchronize();
#endif 
	     }

#ifdef ITERATION
	}
#endif

	// Copy result back to host
	cudaMemcpy(J, d_J, size_I * sizeof(float), cudaMemcpyDeviceToHost);

#ifdef OUTPUT
	  for( int i = 0 ; i < rows ; i++){
		for ( int j = 0 ; j < cols ; j++){

         printf("%.5f ", J[i * cols + j]); 

		}
         printf("\n"); 
   }
#endif 

	printf("Computation Done\n");

	free(I);
	free(J);
	free(iN); free(iS); free(jW); free(jE);
    free(dN); free(dS); free(dW); free(dE);

	free(c);

	// Free CUDA device memory
	cudaFree(d_J);
	cudaFree(d_dN);
	cudaFree(d_dS);
	cudaFree(d_dW);
	cudaFree(d_dE);
	cudaFree(d_c);
	cudaFree(d_iN);
	cudaFree(d_iS);
	cudaFree(d_jW);
	cudaFree(d_jE);

	return 0;
}

